const history = $input.item.json;

// Resolve prompt_id safely
const promptId =
  history.prompt_id ||
  Object.keys(history)[0];

const promptData = history[promptId];

if (!promptData || !promptData.outputs) {
  throw new Error("Video not ready yet or generation failed");
}

// Find ANY output node that contains videos or gifs
let videoInfo = null;

for (const nodeId of Object.keys(promptData.outputs)) {
  const nodeOutput = promptData.outputs[nodeId];

  // Check for videos (from SaveVideo nodes)
  if (nodeOutput?.videos && nodeOutput.videos.length > 0) {
    videoInfo = nodeOutput.videos[0];
    break;
  }

  // Check for gifs (from SaveAnimatedWEBP or similar nodes)
  if (nodeOutput?.gifs && nodeOutput.gifs.length > 0) {
    videoInfo = nodeOutput.gifs[0];
    break;
  }

  // Some video nodes might save under 'images' key for animated formats
  if (nodeOutput?.images && nodeOutput.images.length > 0) {
    const firstImage = nodeOutput.images[0];
    // Check if it's actually a video format
    if (firstImage.filename && (
      firstImage.filename.endsWith('.mp4') || 
      firstImage.filename.endsWith('.webm') ||
      firstImage.filename.endsWith('.gif') ||
      firstImage.filename.endsWith('.webp')
    )) {
      videoInfo = firstImage;
      break;
    }
  }
}

if (!videoInfo) {
  throw new Error("No video found in any output node");
}

// Pull metadata from previous workflow state
const previousData = $input.first().json;

return [
  {
    json: {
      filename: videoInfo.filename,
      subfolder: videoInfo.subfolder || "",
      type: videoInfo.type || "output",
      format: videoInfo.format || "video/mp4",
      seed: previousData.seed ?? null,
      user_prompt: previousData.user_prompt ?? null,
      prompt_id: promptId
    }
  }
];
